  ]
}

parameters.jsonBody:
={
  "textMessage": {
    "text": "Hi {{ $json.Name }}! Your booking for {{ $json.Service }} is confirmed for {{ $json.Date }} at {{ DateTime.fromFormat($json.Start_Time, 'HH:mm').toFormat('hh:mm a') }}."
  },
  "phoneNumbers": [
    "+91{{ $json.Phone }}"
  ]
}

